SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, derivado, regiao, estado, vendas FROM (SELECT make_date(TRY_CAST(trim("ano") AS INTEGER), CASE upper(trim("mes")) WHEN 'JAN' THEN 1 WHEN 'JANEIRO' THEN 1 WHEN 'FEV' THEN 2 WHEN 'FEVEREIRO' THEN 2 WHEN 'MAR' THEN 3 WHEN 'MARÇO' THEN 3 WHEN 'MARCO' THEN 3 WHEN 'ABR' THEN 4 WHEN 'ABRIL' THEN 4 WHEN 'MAI' THEN 5 WHEN 'MAIO' THEN 5 WHEN 'JUN' THEN 6 WHEN 'JUNHO' THEN 6 WHEN 'JUL' THEN 7 WHEN 'JULHO' THEN 7 WHEN 'AGO' THEN 8 WHEN 'AGOSTO' THEN 8 WHEN 'SET' THEN 9 WHEN 'SETEMBRO' THEN 9 WHEN 'OUT' THEN 10 WHEN 'OUTUBRO' THEN 10 WHEN 'NOV' THEN 11 WHEN 'NOVEMBRO' THEN 11 WHEN 'DEZ' THEN 12 WHEN 'DEZEMBRO' THEN 12 ELSE TRY_CAST(trim("mes") AS INTEGER) END, 1) AS date, NULLIF(TRIM("combustivel"), '') AS derivado, NULLIF(TRIM("regiao"), '') AS regiao, NULLIF(TRIM("estado"), '') AS estado, TRY_CAST(replace(replace(trim("vendas"), '.', ''), ',', '.') AS DOUBLE) AS vendas FROM "anp-brazil-vdpb-vendas-por-produtor-vendas-oleo-diesel-produtores-m3") WHERE date IS NOT NULL AND (vendas IS NOT NULL)
